UPDATE users
   SET block_yn = #{blockYn}
 WHERE user_id = #{userId}

UPDATE store
   SET status = #{status}
 WHERE user_id = #{userId}

UPDATE NOTICE
   SET NOTICE_TITLE   = #{noticeTitle}
     , NOTICE_CONTENT = #{noticeContent}
     , UPDATE_DATE    = SYSDATE
 WHERE NOTICE_NO      = #{noticeNo}

UPDATE QNA
   SET ANSWER_CONTENT = #{answerContent}
     , ANSWER_DATE    = SYSDATE
     , STATUS_YN      = '완료'
 WHERE QNA_ID         = #{qnaId}
